module div_8bit
(
    input clk,
    input rst,
    input sign,
    input [7:0] dividend,
    input [7:0] divisor,
    input opn_valid,
    input res_ready,
    output res_valid,
    output reg [15:0] result
);

    reg [15:0] SR;
    reg [7:0] DR;
    reg [3:0] cnt;
    reg [3:0] rem;
    reg [1:0] state;
    parameter IDLE = 2'b00, DIVIDE = 2'b01, DONE = 2'b10;

    assign res_valid = (state == DONE) ? 1'b1 : 1'b0;

    always @(posedge clk or negedge rst) begin
        if (!rst) begin
            SR <= 16'b0;
            DR <= 8'b0;
            cnt <= 4'b0;
            rem <= 4'b0;
            state <= IDLE;
        end else begin
            case (state)
                IDLE: begin
                    if (opn_valid) begin
                        SR <= {8'b0, dividend};
                        DR <= divisor;
                        cnt <= 4'b1000;
                        rem <= 4'b0000;
                        state <= DIVIDE;
                    end
                end
                DIVIDE: begin
                    if (cnt == 4'b0000) begin
                        if (sign && (dividend[7] ^ divisor[7])) begin
                            result <= -SR[15:0];
                        end else begin
                            result <= SR[15:0];
                        end
                        state <= DONE;
                    end else begin
                        if (SR[15:8] >= {1'b0, DR}) begin
                            SR <= {SR[14:0], 1'b0};
                            DR <= DR;
                            SR[15:8] <= SR[15:8] - {1'b0, DR};
                            SR[7:0] <= SR[7:0];
                            cnt <= cnt - 4'b0001;
                            rem <= SR[15:8];
                        end else begin
                            SR <= {SR[14:0], 1'b0};
                            DR <= DR;
                            SR[7:0] <= SR[7:0];
                            cnt <= cnt - 4'b0001;
                            rem <= SR[15:8];
                        end
                    end
                end
                DONE: begin
                    if (res_ready) begin
                        state <= IDLE;
                    end
                end
            endcase
        end
    end

endmodule
